1	'use server'
2	import { revalidatePath } from 'next/cache'
3	import { prisma } from '@/lib/prisma'
4	import { requireAdmin } from '@/lib/auth'
5	import { domainSaveSchema } from './schema'
6	import type { ActionResult } from '@/lib/errors'
7	
8	export async function createDomain(input: unknown): Promise<ActionResult<{ id: number }>> {
9	  await requireAdmin()
10	  const parsed = domainSaveSchema.safeParse(input)
11	  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
12	
13	  let domain: { id: number }
14	  try {
15	    domain = await prisma.domain.create({ data: parsed.data })
16	  } catch {
17	    return { success: false, error: '저장 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
18	  }
19	  revalidatePath('/domain')
20	  return { success: true, data: { id: domain.id } }
21	}
22	
23	export async function updateDomain(id: number, input: unknown): Promise<ActionResult> {
24	  await requireAdmin()
25	  const parsed = domainSaveSchema.safeParse(input)
26	  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
27	
28	  try {
29	    await prisma.domain.update({ where: { id }, data: parsed.data })
30	  } catch {
31	    return { success: false, error: '저장 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
32	  }
33	  revalidatePath('/domain')
34	  return { success: true, data: undefined }
35	}
36	
37	export async function deleteDomain(id: number): Promise<ActionResult> {
38	  await requireAdmin()
39	  try {
40	    await prisma.domain.delete({ where: { id } })
41	  } catch {
42	    return { success: false, error: '삭제 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
43	  }
44	  revalidatePath('/domain')
45	  return { success: true, data: undefined }
46	}
